def gen(rng, size):
    n = max(1, min(size, 100000))
    prices = [rng.randint(1, 100000)]
    for _ in range(n - 1):
        move = rng.choice(['down1', 'down1', 'down_more', 'up', 'flat'])
        last = prices[-1]
        if move == 'down1' and last > 1:
            prices.append(last - 1)
        elif move == 'down_more' and last > 3:
            prices.append(last - rng.randint(2, 3))
        elif move == 'up':
            prices.append(min(100000, last + rng.randint(1, 5)))
        elif move == 'flat':
            prices.append(last)
        else:
            prices.append(rng.randint(1, 100000))
    return [prices]

