class Solution:
    def getDescentPeriods(self, prices):
        n = len(prices)
        total = 0
        for i in range(n):
            total += 1
            j = i
            while j + 1 < n and prices[j + 1] == prices[j] - 1:
                j += 1
                total += 1
        return total

