class Solution:
    def getDescentPeriods(self, prices):
        n = len(prices)
        total = 0
        run = 1
        for i in range(1, n):
            if prices[i] == prices[i - 1] - 1:
                run += 1
            else:
                total += run * (run + 1) // 2
                run = 1
        total += run * (run + 1) // 2
        return total

