var getDescentPeriods = function(prices) {
    const n = prices.length;
    let total = 0;
    let run = 1;
    for (let i = 1; i < n; i++) {
        if (prices[i] === prices[i - 1] - 1) {
            run++;
        } else {
            total += (run * (run + 1)) / 2;
            run = 1;
        }
    }
    total += (run * (run + 1)) / 2;
    return total;
};
